# test_binary_search.py
import pytest

# Adjust this import to match where your function is defined
# from your_module import binary_search


def binary_search(arr: list, target: int) -> int:
    low, high = 0, len(arr) - 1
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1


@pytest.mark.parametrize(
    "arr,target,expected",
    [
        ([1, 2, 3, 4, 5], 1, 0),   # first element
        ([1, 2, 3, 4, 5], 3, 2),   # middle element
        ([1, 2, 3, 4, 5], 5, 4),   # last element
        ([10], 10, 0),             # single-element found
        ([-10, -5, 0, 5, 10], -5, 1),  # negative values
    ],
)
def test_binary_search_found(arr, target, expected):
    assert binary_search(arr, target) == expected


@pytest.mark.parametrize(
    "arr,target",
    [
        ([1, 2, 3, 4, 5], 6),      # greater than all elements
        ([1, 2, 3, 4, 5], 0),      # less than all elements
        ([1, 3, 5, 7], 4),         # between elements
        ([10], 5),                 # single-element not found
        ([], 1),                   # empty list
    ],
)
def test_binary_search_not_found(arr, target):
    assert binary_search(arr, target) == -1


def test_binary_search_with_duplicates_returns_valid_matching_index():
    arr = [1, 2, 2, 2, 3]
    result = binary_search(arr, 2)

    assert result in {1, 2, 3}
    assert arr[result] == 2


def test_binary_search_large_list():
    arr = list(range(0, 10_000, 2))

    assert binary_search(arr, 2468) == 1234
    assert binary_search(arr, 2469) == -1


def test_binary_search_tuple_input_still_works():
    # Although the type hint says list, the implementation works with indexable sequences.
    arr = (1, 2, 3, 4, 5)

    assert binary_search(arr, 4) == 3


def test_binary_search_none_array_raises_type_error():
    with pytest.raises(TypeError):
        binary_search(None, 1)


def test_binary_search_mixed_incomparable_types_raises_type_error():
    arr = [1, 2, "3", 4]

    with pytest.raises(TypeError):
        binary_search(arr, 3)


def test_binary_search_unsorted_array_behavior_not_guaranteed():
    # Binary search requires sorted input. This test documents that unsorted input
    # should not be relied upon.
    arr = [3, 1, 2]

    result = binary_search(arr, 1)

    assert result in {-1, 1}
